package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileReader;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    private File mockFile;
    private CSVFormat mockFormat;
    private FileReader mockFileReader;

    @BeforeEach
    void setUp() throws Exception {
        mockFile = mock(File.class);
        mockFormat = mock(CSVFormat.class);
        mockFileReader = mock(FileReader.class);
    }

    @Test
    void parse_NullFile_ThrowsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((File) null, mockFormat);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void parse_NullFormat_ThrowsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockFile, null);
        });
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void parse_ValidFileAndFormat_ReturnsCSVParser() throws IOException {
        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class);
             MockedStatic<CSVParser> mockedCSVParser = Mockito.mockStatic(CSVParser.class, Mockito.CALLS_REAL_METHODS)) {

            mockedAssertions.when(() -> Assertions.notNull(mockFile, "file")).thenCallRealMethod();
            mockedAssertions.when(() -> Assertions.notNull(mockFormat, "format")).thenCallRealMethod();

            // We cannot mock constructor easily, so we spy on CSVParser class to call real constructor
            CSVParser parser = CSVParser.parse(mockFile, mockFormat);

            assertNotNull(parser);
            assertEquals(mockFormat, getField(parser, "format"));
        }
    }

    private <T> T getField(Object instance, String fieldName) {
        try {
            java.lang.reflect.Field field = instance.getClass().getDeclaredField(fieldName);
            field.setAccessible(true);
            @SuppressWarnings("unchecked")
            T value = (T) field.get(instance);
            return value;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
